left = imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"));
right = imread(fullpath(getIPCVpath() + "/images/opencv_left02.jpg"));
leftFeatures = imdetect_AKAZE(left);
rightFeatures = imdetect_AKAZE(right);
imshow(left);
plotfeature(leftFeatures);
title("AKAZE features");

image = imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg"));
features = imdetect_AKAZE(image);
imshow(image);
plotfeature(features);
title("AKAZE features on fruits");
